# Open a draft PR that updates ONLY sdk/ai/ai-projects/assets.json after re-recording.
#
# Usage:
#   ./open-assets-pr.ps1 [-BranchName <name>] [-Remote origin]
#
# Commits the single-file assets.json change, pushes to origin (never force),
# and opens a DRAFT PR via `gh`. Run from sdk/ai/ai-projects/.

[CmdletBinding()]
param(
  [string]$BranchName,
  [string]$Remote = 'origin'
)

$ErrorActionPreference = 'Stop'

$repoRoot = (& git rev-parse --show-toplevel).Trim()
if (-not $repoRoot) { throw "Not inside a git repo." }
$assetsRel = 'sdk/ai/ai-projects/assets.json'

if (-not $BranchName) {
  $stamp = (Get-Date).ToString('yyyyMMdd-HHmm')
  $BranchName = "rerecord/ai-projects/$stamp"
}

Push-Location $repoRoot
try {
  # 1. assets.json must actually have changed.
  $assetsChanged = & git status --porcelain -- $assetsRel
  if (-not $assetsChanged) {
    throw "No change to $assetsRel. Did you run rerecord.ps1 -Push (or 'dev-tool test-proxy push') first?"
  }

  # 2. This PR may touch ONLY assets.json. Refuse if anything else is staged-able.
  $other = & git status --porcelain | Where-Object {
    $_ -and ($_ -notmatch ([regex]::Escape($assetsRel) + '$'))
  }
  if ($other) {
    throw "Refusing to proceed: changes detected outside ${assetsRel}:`n$($other -join "`n")`n`nThis skill only publishes assets.json. Commit/stash other changes separately."
  }

  # 3. Read the new tag for the PR body.
  $assetsJson = Get-Content (Join-Path $repoRoot $assetsRel) -Raw | ConvertFrom-Json
  $newTag = $assetsJson.Tag

  # 4. Branch from HEAD.
  Write-Host "Creating branch $BranchName"
  & git switch -c $BranchName
  if ($LASTEXITCODE -ne 0) { throw "git switch -c $BranchName failed." }

  # 5. Commit only assets.json.
  & git add -- $assetsRel
  & git commit -m "[ai-projects] Re-record tests: update assets.json" | Out-Null
  if ($LASTEXITCODE -ne 0) { throw "git commit failed." }

  # 6. Push (no force).
  Write-Host "Pushing $BranchName to $Remote"
  & git push --set-upstream $Remote $BranchName
  if ($LASTEXITCODE -ne 0) { throw "git push failed." }

  # 7. Open a draft PR.
  $title = "[ai-projects] Re-record tests: update assets.json"
  $body = @"
Refreshes the recorded test recordings for ``@azure/ai-projects`` and updates
the asset-sync ``Tag`` in ``assets.json``.

**New assets tag**: [``$newTag``](https://github.com/Azure/azure-sdk-assets/tree/$newTag)

Recordings live in ``Azure/azure-sdk-assets`` (asset-sync workflow), so this PR
intentionally touches only ``sdk/ai/ai-projects/assets.json``.

## How these recordings were produced

1. ``TEST_MODE=record npm run test:node`` against live Foundry resources.
2. ``TEST_MODE=playback npm run test:node`` (no live env vars) to verify the
   recordings are self-contained. Only specs that pass playback were published.
3. ``npx dev-tool test-proxy push`` to upload recordings and bump the ``Tag``.

## Verification checklist

- [ ] ``TEST_MODE=playback npm run test:node`` is green against the new tag
- [ ] ``git diff -- assets.json`` shows only the ``Tag`` line changed
- [ ] CI recorded-test job passes

## Generated by
``rerecord-tests`` skill in ``sdk/ai/ai-projects/.github/skills/``.
"@

  $bodyFile = New-TemporaryFile
  Set-Content -Path $bodyFile -Value $body -NoNewline
  try {
    & gh pr create --draft --title $title --body-file $bodyFile --base main --head $BranchName
    if ($LASTEXITCODE -ne 0) { throw "gh pr create failed." }
  }
  finally {
    Remove-Item $bodyFile -Force -ErrorAction SilentlyContinue
  }

  Write-Host ""
  Write-Host "Draft PR opened on branch $BranchName (assets.json only)." -ForegroundColor Green
}
finally {
  Pop-Location
}
